+#!/usr/bin/env gjs
+import { describe, it, assertEqual, assertDeepEqual, assertTrue, printResults } from './run.js';
+import { MonitorGrid } from '../lib/gridEngine.js';
+import { InPlacePlacer, ShelfPlacer, PackPlacer } from '../lib/stampPlacer.js';
+
+describe('InPlacePlacer', () => {
+    it('places stamp at the window current position', () => {
+        const grid = new MonitorGrid(1920, 1080, 8, 6);
+        grid.placeWindow('win1', 4, 3);
+        const placer = new InPlacePlacer();
+        const pos = placer.placeStamp(grid, 'win1', 1, 1);
+        // Should stay at original position (0,0)
+        assertEqual(pos.col, 0);
+        assertEqual(pos.row, 0);
+    });
+});
+
+describe('ShelfPlacer', () => {
+    it('places stamps along bottom edge', () => {
+        const grid = new MonitorGrid(1920, 1080, 8, 6);
+        const placer = new ShelfPlacer('bottom', 2);
+        const pos1 = placer.placeStamp(grid, 'stamp1', 1, 1);
+        assertEqual(pos1.row, 5); // bottom row
+        assertEqual(pos1.col, 0);
+        const pos2 = placer.placeStamp(grid, 'stamp2', 1, 1);
+        assertEqual(pos2.row, 5);
+        assertEqual(pos2.col, 1);
+    });
+
+    it('wraps to next row when shelf row is full', () => {
+        const grid = new MonitorGrid(1920, 1080, 8, 6);
+        const placer = new ShelfPlacer('bottom', 2);
+        // Fill bottom row
+        for (let i = 0; i < 8; i++)
