+/**
+ * Maintains an ordered focus-rank list.
+ * Index 0 = most recently focused. Pure logic, no GNOME Shell dependencies.
+ */
+export class FocusRankList {
+    constructor() {
+        /** @type {string[]} ordered by focus recency, index 0 = most recent */
+        this._ranks = [];
+    }
+
+    /**
+     * Record a window gaining focus. Moves it to rank 0.
+     * @param {string} windowId
+     */
+    onFocus(windowId) {
+        const idx = this._ranks.indexOf(windowId);
+        if (idx !== -1)
+            this._ranks.splice(idx, 1);
+        this._ranks.unshift(windowId);
+    }
+
+    /**
+     * Remove a window from the rank list.
+     */
+    remove(windowId) {
+        const idx = this._ranks.indexOf(windowId);
+        if (idx !== -1)
+            this._ranks.splice(idx, 1);
+    }
+
+    /**
+     * Get the rank (0-based) of a window. -1 if not found.
+     */
+    getRank(windowId) {
+        return this._ranks.indexOf(windowId);
+    }
+
+    /**
+     * Get all ranks as an array (index 0 = most recent).
+     */
+    getRanks() {
+        return [...this._ranks];
+    }
+
+    /**
+     * Get window IDs that are ranked below the threshold.
+     * @param {number} threshold - number of top-ranked windows to keep
+     * @returns {string[]} window IDs below threshold, ordered by rank (highest rank first)
+     */
+    windowsBelowRank(threshold) {
+        if (this._ranks.length <= threshold)
+            return [];
+        return this._ranks.slice(threshold);
+    }
+
+    /**
+     * Get the lowest-ranked window, optionally excluding a set.
+     * @param {Set<string>} exclude - window IDs to skip
+     * @returns {string | null}
+     */
+    getLowestRanked(exclude = new Set()) {
+        for (let i = this._ranks.length - 1; i >= 0; i--) {
+            if (!exclude.has(this._ranks[i]))
+                return this._ranks[i];
+        }
+        return null;
+    }
+
+    get length() {
+        return this._ranks.length;
+    }
+}
+```
