+import Clutter from 'gi://Clutter';
+import Shell from 'gi://Shell';
+import St from 'gi://St';
+import { MIN_SCALE } from './constants.js';
+
+/**
+ * Per-window scaling state.
+ */
+class WindowScaleState {
+    constructor() {
+        this.scaleFactor = 1.0;
+        this.scaleSource = 'auto';       // 'auto' | 'manual'
+        this.previousScaleFactor = 1.0;
+        this.previousCellAllocation = null; // {col, row, spanCols, spanRows}
+        this.clone = null;
+        this.container = null;
+        this.sizeChangedId = 0;
+        this.shrunkTimestamp = 0;         // GLib.get_monotonic_time() when auto-shrunk
+    }
+}
+
+export class ScaleManager {
+    constructor() {
+        /** @type {Map<Meta.Window, WindowScaleState>} */
+        this._states = new Map();
+        this._dragFinalizing = false;
+    }
+
+    getState(metaWindow) {
+        return this._states.get(metaWindow) || null;
+    }
+
+    getOrCreateState(metaWindow) {
+        if (!this._states.has(metaWindow))
+            this._states.set(metaWindow, new WindowScaleState());
+        return this._states.get(metaWindow);
+    }
+
+    /**
+     * Create a clone+container for a scaled window.
+     * @param {Meta.Window} metaWindow
+     * @param {number} scaleFactor
+     * @param {Function} onActivate - called when container is clicked
+     * @returns {{clone: Clutter.Clone, container: St.Widget}}
+     */
+    createClone(metaWindow, scaleFactor, onActivate) {
+        const windowActor = metaWindow.get_compositor_private();
+        if (!windowActor)
+            return null;
+
+        const state = this.getOrCreateState(metaWindow);
+
+        // Hide real actor from pick and make transparent
+        Shell.util_set_hidden_from_pick(windowActor, true);
+        windowActor.opacity = 0;
+
+        // Get source dimensions
+        const frameRect = metaWindow.get_frame_rect();
+        const scaledWidth = Math.round(frameRect.width * scaleFactor);
+        const scaledHeight = Math.round(frameRect.height * scaleFactor);
+
+        // Create clone — it auto-scales source to fit its allocation
+        const clone = new Clutter.Clone({
+            source: windowActor,
+            reactive: false,
+            width: scaledWidth,
+            height: scaledHeight,
+        });
+
+        // Create reactive container
+        const container = new St.Widget({
+            reactive: true,
+            width: scaledWidth,
+            height: scaledHeight,
+            can_focus: true,
+        });
+        container.add_child(clone);
+
+        // Click handler — only calls activate, restore logic is in focusTracker
+        container.connect('button-press-event', (_actor, event) => {
+            if (event.get_button() === Clutter.BUTTON_PRIMARY) {
+                onActivate(metaWindow);
+                return Clutter.EVENT_STOP;
+            }
+            return Clutter.EVENT_PROPAGATE;
+        });
+
+        // Track source geometry changes
+        state.sizeChangedId = metaWindow.connect('size-changed', () => {
+            if (this._dragFinalizing)
+                return;
+            this._updateCloneSize(metaWindow);
+        });
+
+        state.clone = clone;
+        state.container = container;
+        state.scaleFactor = scaleFactor;
+
+        return {clone, container};
+    }
+
+    /**
+     * Update clone/container dimensions after source resize.
+     */
+    _updateCloneSize(metaWindow) {
+        const state = this.getState(metaWindow);
+        if (!state || !state.clone)
+            return;
+
+        const frameRect = metaWindow.get_frame_rect();
+        const scaledWidth = Math.round(frameRect.width * state.scaleFactor);
+        const scaledHeight = Math.round(frameRect.height * state.scaleFactor);
+
+        state.clone.set_size(scaledWidth, scaledHeight);
+        state.container.set_size(scaledWidth, scaledHeight);
+    }
+
+    /**
+     * Destroy clone and restore real actor.
+     */
+    destroyClone(metaWindow) {
+        const state = this.getState(metaWindow);
+        if (!state)
+            return;
+
+        if (state.sizeChangedId) {
+            metaWindow.disconnect(state.sizeChangedId);
+            state.sizeChangedId = 0;
+        }
+
+        if (state.container) {
+            state.container.destroy();
+            state.container = null;
+        }
+        // clone is destroyed as child of container
+        state.clone = null;
+
+        // Restore real actor
+        const windowActor = metaWindow.get_compositor_private();
+        if (windowActor) {
+            Shell.util_set_hidden_from_pick(windowActor, false);
+            windowActor.opacity = 255;
+        }
+    }
+
+    /**
+     * Auto-shrink a window to MIN_SCALE.
+     */
+    autoShrink(metaWindow, currentCellAllocation) {
+        const state = this.getOrCreateState(metaWindow);
+        // Only save previous state on first auto-shrink
+        if (state.scaleSource !== 'auto' || state.scaleFactor > MIN_SCALE + 0.001) {
+            state.previousScaleFactor = state.scaleFactor;
+            state.previousCellAllocation = currentCellAllocation
+                ? {...currentCellAllocation}
+                : null;
+        }
+        state.scaleFactor = MIN_SCALE;
+        state.scaleSource = 'auto';
+        state.shrunkTimestamp = GLib.get_monotonic_time();
+    }
+
+    /**
+     * Restore an auto-shrunk window.
+     * @returns {number} the scale to restore to
+     */
+    autoRestore(metaWindow) {
+        const state = this.getState(metaWindow);
+        if (!state)
+            return 1.0;
+        const restoreScale = state.previousScaleFactor;
+        state.scaleFactor = restoreScale;
+        state.scaleSource = restoreScale < 1.0 - 0.001 ? 'manual' : 'auto';
+        state.shrunkTimestamp = 0;
+        return restoreScale;
+    }
+
+    /**
+     * Manually set scale (user zoomed with keybind).
+     */
+    manualScale(metaWindow, newScale) {
+        const state = this.getOrCreateState(metaWindow);
+        state.scaleFactor = newScale;
+        state.scaleSource = newScale > 1.0 - 0.001 ? 'auto' : 'manual';
+    }
+
+    /**
+     * Check if a window can be bumped (auto-shrink eligible).
+     */
+    canBump(metaWindow, exemptApps) {
+        const state = this.getState(metaWindow);
+        if (!state)
+            return true; // untracked window defaults to auto, non-exempt
+        if (state.scaleSource === 'manual')
+            return false;
+        // Check exempt status via app ID
+        const app = Shell.WindowTracker.get_default().get_window_app(metaWindow);
+        const appId = app ? app.get_id() : (metaWindow.get_wm_class() || '');
+        return !exemptApps.includes(appId);
+    }
+
+    /**
+     * Check if a window was recently auto-shrunk (within hysteresis window).
+     */
+    isRecentlyShrunk(metaWindow, hysteresisMs) {
+        const state = this.getState(metaWindow);
+        if (!state || state.shrunkTimestamp === 0)
+            return false;
+        const elapsed = (GLib.get_monotonic_time() - state.shrunkTimestamp) / 1000;
+        return elapsed < hysteresisMs;
+    }
+
+    setDragFinalizing(val) {
+        this._dragFinalizing = val;
+    }
+
+    removeState(metaWindow) {
+        this.destroyClone(metaWindow);
+        this._states.delete(metaWindow);
+    }
+
+    /**
+     * Suspend all clones for Overview.
+     */
+    suspendAll() {
+        for (const [metaWindow, state] of this._states) {
+            if (!state.container)
+                continue;
+            state.container.visible = false;
+            const windowActor = metaWindow.get_compositor_private();
+            if (windowActor) {
+                Shell.util_set_hidden_from_pick(windowActor, false);
+                windowActor.opacity = 255;
+            }
+        }
+    }
+
+    /**
+     * Restore all clones after Overview.
+     */
+    restoreAll() {
+        for (const [metaWindow, state] of this._states) {
+            if (!state.container)
+                continue;
+            state.container.visible = true;
+            const windowActor = metaWindow.get_compositor_private();
+            if (windowActor) {
+                Shell.util_set_hidden_from_pick(windowActor, true);
+                windowActor.opacity = 0;
+            }
+        }
+    }
+
+    /**
+     * Clean up all state (for disable()).
+     */
+    destroyAll() {
+        for (const metaWindow of this._states.keys())
+            this.destroyClone(metaWindow);
+        this._states.clear();
+    }
+}
