+import Clutter from 'gi://Clutter';
+import GLib from 'gi://GLib';
+import Meta from 'gi://Meta';
+import St from 'gi://St';
+
+export class DragHandler {
+    /**
+     * @param {object} params
+     * @param {Meta.Display} params.display
+     * @param {Clutter.Actor} params.windowGroup - global.window_group
+     * @param {Clutter.Actor} params.topWindowGroup - global.top_window_group
+     * @param {Function} params.getGridForMonitor - (monitorIndex) => MonitorGrid
+     * @param {Function} params.getMonitorGeometry - (monitorIndex) => {x,y,width,height}
+     * @param {Function} params.getMonitorCount - () => number
+     * @param {Function} params.getWindowScaleState - (metaWindow) => WindowScaleState
+     * @param {Function} params.onDropFullSize - (metaWindow, monitorIndex, col, row)
+     * @param {Function} params.onDropStamp - (metaWindow, monitorIndex, col, row)
+     * @param {InputRouter} params.inputRouter
+     */
+    constructor(params) {
+        this._display = params.display;
+        this._windowGroup = params.windowGroup;
+        this._topWindowGroup = params.topWindowGroup;
+        this._getGridForMonitor = params.getGridForMonitor;
+        this._getMonitorGeometry = params.getMonitorGeometry;
+        this._getMonitorCount = params.getMonitorCount;
+        this._getWindowScaleState = params.getWindowScaleState;
+        this._onDropFullSize = params.onDropFullSize;
+        this._onDropStamp = params.onDropStamp;
+        this._inputRouter = params.inputRouter;
+
+        // Drag state
+        this._dragActive = false;
+        this._dragWindow = null;
+        this._dragTimerId = 0;
+        this._targetMonitor = -1;
+        this._targetCol = -1;
+        this._targetRow = -1;
+        this._clutterGrab = null;
+
+        // Grid overlay
+        this._overlay = new St.Widget({
+            style_class: 'mutter-butter-grid-overlay',
+            reactive: false,
+            visible: false,
+        });
+        this._windowGroup.add_child(this._overlay);
+
+        // Connect grab-op signals
+        this._grabBeginId = this._display.connect('grab-op-begin',
+            (_display, window, grabOp) => this._onGrabBegin(window, grabOp));
+        this._grabEndId = this._display.connect('grab-op-end',
+            (_display, window, _grabOp) => this._onGrabEnd(window));
+    }
+
+    _onGrabBegin(metaWindow, grabOp) {
+        if (!metaWindow)
+            return;
+        const normalized = grabOp & ~1024;
+        if (normalized !== Meta.GrabOp.MOVING &&
+            normalized !== Meta.GrabOp.KEYBOARD_MOVING)
+            return;
+
+        // Only handle full-size windows here; stamps use manual drag
+        const state = this._getWindowScaleState(metaWindow);
+        if (state && state.scaleFactor < 1.0 - 0.001)
+            return;
+
+        this._startDrag(metaWindow);
+    }
+
+    _onGrabEnd(metaWindow) {
+        if (!this._dragActive || this._dragWindow !== metaWindow)
+            return;
+        this._finishFullSizeDrag(metaWindow);
+    }
+
+    _startDrag(metaWindow) {
+        this._dragActive = true;
+        this._dragWindow = metaWindow;
+        this._showOverlay();
+
+        this._dragTimerId = GLib.timeout_add(GLib.PRIORITY_DEFAULT, 16, () => {
+            this._updateDragPosition();
+            return GLib.SOURCE_CONTINUE;
+        });
+    }
+
+    _updateDragPosition() {
+        const [x, y] = global.get_pointer();
+        const monitor = this._monitorAtPoint(x, y);
+        if (monitor < 0)
+            return;
+
+        const grid = this._getGridForMonitor(monitor);
+        if (!grid)
+            return;
+
+        const geo = this._getMonitorGeometry(monitor);
+        const localX = x - geo.x;
+        const localY = y - geo.y;
+        const cell = grid.pixelsToCell(localX, localY);
+
+        this._targetMonitor = monitor;
+        this._targetCol = cell.col;
+        this._targetRow = cell.row;
+
+        this._updateOverlayHighlight(monitor, cell.col, cell.row);
+    }
+
+    _monitorAtPoint(x, y) {
+        const n = this._getMonitorCount();
+        for (let i = 0; i < n; i++) {
+            const geo = this._getMonitorGeometry(i);
+            if (x >= geo.x && x < geo.x + geo.width &&
+                y >= geo.y && y < geo.y + geo.height)
+                return i;
+        }
+        return -1;
+    }
+
+    _showOverlay() {
+        this._overlay.visible = true;
+    }
+
+    _hideOverlay() {
+        this._overlay.visible = false;
+        this._overlay.destroy_all_children();
+    }
+
+    _updateOverlayHighlight(monitorIndex, col, row) {
+        // Simplified: just reposition overlay to show target cell
+        const grid = this._getGridForMonitor(monitorIndex);
+        const geo = this._getMonitorGeometry(monitorIndex);
+        if (!grid)
+            return;
+
+        this._overlay.destroy_all_children();
+        this._overlay.set_position(geo.x, geo.y);
+        this._overlay.set_size(geo.width, geo.height);
+
+        const highlight = new St.Widget({
+            style_class: 'mutter-butter-grid-cell-target',
+            x: col * grid.cellWidth,
+            y: row * grid.cellHeight,
+            width: grid.cellWidth,
+            height: grid.cellHeight,
+        });
+        this._overlay.add_child(highlight);
+    }
+
+    _finishFullSizeDrag(metaWindow) {
+        this._stopPolling();
+        this._hideOverlay();
+
+        if (this._targetMonitor >= 0 && this._targetCol >= 0) {
+            const monitor = this._targetMonitor;
+            const col = this._targetCol;
+            const row = this._targetRow;
+            GLib.idle_add(GLib.PRIORITY_DEFAULT, () => {
+                this._onDropFullSize(metaWindow, monitor, col, row);
+                return GLib.SOURCE_REMOVE;
+            });
+        }
+
+        this._clearDragState();
+    }
+
+    /**
+     * Start a manual stamp drag. Called from container button-press handler.
+     */
+    startStampDrag(metaWindow, container) {
+        this._dragActive = true;
+        this._dragWindow = metaWindow;
+
+        this._inputRouter.reparentForDrag(container, this._topWindowGroup);
+        this._clutterGrab = global.stage.grab(container);
+
+        container.connect('motion-event', (_actor, event) => {
+            if (!this._dragActive)
+                return Clutter.EVENT_PROPAGATE;
+            const [x, y] = event.get_coords();
+            container.set_position(x - container.width / 2, y - container.height / 2);
+            this._updateDragPosition();
+            return Clutter.EVENT_STOP;
+        });
+
+        container.connect('button-release-event', (_actor, _event) => {
+            if (!this._dragActive)
+                return Clutter.EVENT_PROPAGATE;
+            this._finishStampDrag(metaWindow, container);
+            return Clutter.EVENT_STOP;
+        });
+
+        this._showOverlay();
+    }
+
+    _finishStampDrag(metaWindow, container) {
+        if (this._clutterGrab) {
+            this._clutterGrab.dismiss();
+            this._clutterGrab = null;
+        }
+
+        this._hideOverlay();
+        this._inputRouter.reparentFromDrag(container);
+
+        if (this._targetMonitor >= 0 && this._targetCol >= 0) {
+            const monitor = this._targetMonitor;
+            const col = this._targetCol;
+            const row = this._targetRow;
+            GLib.idle_add(GLib.PRIORITY_DEFAULT, () => {
+                this._onDropStamp(metaWindow, monitor, col, row);
+                return GLib.SOURCE_REMOVE;
+            });
+        }
+
+        this._clearDragState();
+    }
+
+    /**
+     * Cancel drag due to window destruction.
+     */
+    cancelDrag() {
+        if (!this._dragActive)
+            return;
+        this._stopPolling();
+        if (this._clutterGrab) {
+            this._clutterGrab.dismiss();
+            this._clutterGrab = null;
+        }
+        this._hideOverlay();
+        this._clearDragState();
+    }
+
+    _stopPolling() {
+        if (this._dragTimerId) {
+            GLib.source_remove(this._dragTimerId);
+            this._dragTimerId = 0;
+        }
+    }
+
+    _clearDragState() {
+        this._dragActive = false;
+        this._dragWindow = null;
+        this._targetMonitor = -1;
+        this._targetCol = -1;
+        this._targetRow = -1;
+    }
+
+    get isDragging() {
+        return this._dragActive;
+    }
+
+    get dragWindow() {
+        return this._dragWindow;
+    }
+
+    destroy() {
+        this.cancelDrag();
+        if (this._grabBeginId) {
+            this._display.disconnect(this._grabBeginId);
+            this._grabBeginId = 0;
+        }
+        if (this._grabEndId) {
+            this._display.disconnect(this._grabEndId);
+            this._grabEndId = 0;
+        }
+        this._overlay.destroy();
+    }
+}
