+```javascript
+import Meta from 'gi://Meta';
+import { MANAGED_WINDOW_TYPES } from './constants.js';
+
+/**
+ * Determines how a window should be handled based on its current state.
+ */
+export class WindowStateHandler {
+    /**
+     * Check if a window type should be managed by the grid.
+     */
+    static isManaged(metaWindow) {
+        return MANAGED_WINDOW_TYPES.includes(metaWindow.get_window_type());
+    }
+
+    /**
+     * Check if a window is fullscreen (bypasses grid, implicitly exempt).
+     */
+    static isFullscreen(metaWindow) {
+        return metaWindow.is_fullscreen();
+    }
+
+    /**
+     * Check if a window is maximized (occupies all cells, implicitly exempt).
+     */
+    static isMaximized(metaWindow) {
+        return metaWindow.get_maximized() === Meta.MaximizeFlags.BOTH;
+    }
+
+    /**
+     * Check if a window is tiled (half-maximized).
+     */
+    static isTiled(metaWindow) {
+        const maximized = metaWindow.get_maximized();
+        return maximized === Meta.MaximizeFlags.HORIZONTAL ||
+               maximized === Meta.MaximizeFlags.VERTICAL;
+    }
+
+    /**
+     * Check if a window is minimized.
+     */
+    static isMinimized(metaWindow) {
+        return metaWindow.minimized;
+    }
+
+    /**
+     * Check if a window should be implicitly exempt from auto-shrink.
+     */
+    static isImplicitlyExempt(metaWindow) {
+        return WindowStateHandler.isFullscreen(metaWindow) ||
+               WindowStateHandler.isMaximized(metaWindow);
+    }
+
+    /**
+     * Unmaximize a window before scaling.
+     */
+    static unmaximizeForScale(metaWindow) {
+        if (WindowStateHandler.isMaximized(metaWindow))
+            metaWindow.unmaximize(Meta.MaximizeFlags.BOTH);
+        else if (WindowStateHandler.isTiled(metaWindow))
+            metaWindow.unmaximize(metaWindow.get_maximized());
+    }
+}
